#include<bits/stdc++.h>
using namespace std;
const int N=1005,Mod=19650827;
long long a[N],dp[N][N][2],n;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        dp[i][i][0]=1;
    }
    for(int len=2;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            if(a[l]<a[r]) dp[l][r][0]+=dp[l+1][r][1],dp[l][r][1]=dp[l][r-1][0];
            if(a[r]>a[r-1]) dp[l][r][1]+=dp[l][r-1][1];
            if(a[l]<a[l+1]) dp[l][r][0]+=dp[l+1][r][0];
            dp[l][r][0]%=Mod,dp[l][r][1]%=Mod;
        }
    }
    cout<<(dp[1][n][0]+dp[1][n][1])%Mod;
    return 0;
}
